from typing import Any, Dict


def update_profile(user: Dict[str, Any], changes: Dict[str, Any]) -> Dict[str, Any]:
    """Update user profile fields from changes dict and return the same user dict.

    The function expects both user and changes to be dictionaries. Supported
    updatable fields are: 'name', 'email', and 'age'.

    Important: 'display_name' is derived from 'name' and cannot be set
    directly via changes; it will be kept in sync automatically whenever
    'name' is updated.

    Unknown keys in changes are ignored.
    """
    if not isinstance(user, dict):
        raise TypeError("user must be a dict")
    if not isinstance(changes, dict):
        raise TypeError("changes must be a dict")

    for key, value in changes.items():
        if key == "name":
            # Always keep display_name in sync with name.
            user["name"] = value
            user["display_name"] = value
        elif key == "email":
            user["email"] = value
        elif key == "age":
            user["age"] = value
        elif key == "display_name":
            # Ignore direct updates to display_name to preserve the invariant.
            continue
        else:
            # Unknown keys are ignored to keep update semantics simple.
            continue

    return user


def create_user(name: str, email: str) -> Dict[str, Any]:
    """Create a new user profile with a synced display_name."""
