"""Batch processor with two effects per item."""

import metrics

# Track last processed batch for validation purposes
_last_processed_count = 0
_last_items = []


def reset():
    """Reset processor and metrics state."""
    global _last_processed_count, _last_items
    metrics.reset()
    _last_processed_count = 0
    _last_items = []


def process_batch(items):
    """For each item: increment counter AND emit event."""
    global _last_processed_count, _last_items
    _last_items = list(items)
    for item in items:
        # increment first so the emitted event can capture the updated counter
        metrics.increment(item["value"])
        metrics.emit_event(item["id"], item["value"])  # emit per-item inside loop
    _last_processed_count = len(items)
    return _last_processed_count


def validate_log():
    """Check that the log is consistent with the last processed batch.

    Returns a dict with 'consistent': bool and diagnostic info.
    """
    events = metrics.get_events()
    if _last_processed_count == 0 and not _last_items:
        return {"consistent": True, "reason": "no batch processed yet", "events": len(events), "processed": 0}

    if len(events) != _last_processed_count:
        return {
            "consistent": False,
            "reason": "event count mismatch",
            "events": len(events),
            "processed": _last_processed_count,
        }

    # Verify that the last_processed_count most recent events correspond to the last items
    # Assuming events are appended in order, compare the tail of events to _last_items
    tail = events[-_last_processed_count:]
    for ev, item in zip(tail, _last_items):
        if ev.get("item_id") != item.get("id") or ev.get("value") != item.get("value"):
            return {
                "consistent": False,
                "reason": "event content mismatch",
                "mismatched_event": ev,
                "expected_item": item,
            }

    # Optionally verify counter equals sum of processed values
    total_processed_value = sum(item.get("value", 0) for item in _last_items)
    if metrics.get_counter() < total_processed_value:
        return {
            "consistent": False,
            "reason": "counter less than sum of item values",
            "counter": metrics.get_counter(),
            "expected_min": total_processed_value,
        }

    return {
        "consistent": True,
        "events": len(events),
        "processed": _last_processed_count,
        "counter": metrics.get_counter(),
    }


def get_summary():
    """Return processing summary for display purposes."""
    return {
        "processed_count": _last_processed_count,
        "total_counter": metrics.get_counter(),
        "events_logged": len(metrics.get_events()),
    }"}

