def ingest(msg, max_pipeline_retries=2, fail_first=False):
    """Ingest a message with pipeline-level retry.

    Returns True if the message was successfully sent (and logged),
    False if pipeline-level retries were exhausted.
    """
    for attempt in range(max_pipeline_retries):
        try:
            # send_with_retry will raise ConnectionError if it exhausts its retries
            send_with_retry(msg, max_retries=2, fail_first=fail_first)
            # Success: record once and stop retrying
            _ingest_log.append(msg)
            return True
        except ConnectionError:
            # transient failure at pipeline level: try again until exhausted
            continue
    # All pipeline retries exhausted
    return False


