from state import make_state
from reducers import normalize, collapse, stage, commit, freeze_view, materialize


def process_batch(entries):
    st = make_state(entries)
    cleaned = normalize(st["raw"])
    merged = collapse(cleaned)
    stage(st, merged)
    # commit and freeze_view are required to promote pending to stable and
    # to rebuild the view from the committed data so selectors relying on
    # committed state work correctly.
    commit(st)
    freeze_view(st)
    return st, materialize(st)

