    run_steps will retry blocked steps until all complete or until a full
    pass makes no progress (true deadlock detected).
    """
    results = []
    pending = list(steps)
    while pending:
        progressed = False
        new_pending = []
        for fn, args in pending:
            try:
                res = fn(*args)
            except RuntimeError:
                # Treat unexpected RuntimeError as blocked for cooperative retry
                res = "blocked"
            if res == "blocked":
                new_pending.append((fn, args))
            else:
                results.append(res)
                progressed = True
        if not progressed:
            raise RuntimeError("deadlock: no progress (detected)")
        pending = new_pending
    return results

def make_transfer_a_to_b_steps(amount):
    """Transfer A→B: acquire both locks in a consistent global order."""

    resources = sorted(["A", "B"])  # canonical global order

    def step_lock_both():
        acquired = []
        for r in resources:
            if not try_acquire(r):
                # release any locks we acquired during this attempt
                for a in acquired:
                    release(a)
                return "blocked"
            acquired.append(r)
        return "locked_both_A_B"

    def step_transfer_and_release():
        # only perform the transfer if both locks are held
        for r in resources:
            if not _locks.get(r):
                return "blocked"
        _state["A"] -= amount
        _state["B"] += amount
        # release in reverse order
        for r in reversed(resources):
            release(r)
        return "transferred_a_to_b"

    return step_lock_both, step_transfer_and_release

def make_transfer_b_to_a_steps(amount):
    """Transfer B→A: acquire locks in the same global order as A→B to avoid deadlock."""

    resources = sorted(["A", "B"])  # same canonical order as above

    def step_lock_both():
        acquired = []
        for r in resources:
            if not try_acquire(r):
                for a in acquired:
                    release(a)
                return "blocked"
            acquired.append(r)
        return "locked_both_A_B"

    def step_transfer_and_release():
        for r in resources:
            if not _locks.get(r):
                return "blocked"
        _state["B"] -= amount
        _state["A"] += amount
        for r in reversed(resources):
            release(r)
        return "transferred_b_to_a"

    return step_lock_both, step_transfer_and_release

def sequential_transfers():
    """A→B then B→A. Sequential: works fine."""
    reset()
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)
    run_steps([
        (lock_ab, ()), (do_ab, ()),
        (lock_ba, ()), (do_ba, ()),
    ])
    return get_state()

def interleaved_transfers():
    """A→B and B→A interleaved: cooperative scheduler prevents deadlock."""
    reset()
    lock_ab, do_ab = make_transfer_a_to_b_steps(10)
    lock_ba, do_ba = make_transfer_b_to_a_steps(10)
    try:
        run_steps([
            (lock_ab, ()),   # A→B lock attempt (acquires both in canonical order)
            (lock_ba, ()),   # B→A lock attempt (will block if locks not available)
            (do_ab, ()),     # A→B transfer (runs only when it holds both locks)
            (do_ba, ()),     # B→A transfer (runs only when it holds both locks)
        ])
        return get_state()
    except RuntimeError as e:
        return {"error": str(e)}
